.tabs {
  width: 100%;
  height: 100%;
  padding: 4vw 7vw;
}

.tabs__header {
  position: relative;
  border-bottom: 1px solid rgba(0, 0, 0, 0.1);
}

.tabs__labels {
  display: flex;
  gap: 2vw;
  overflow-x: auto;
}

.tabs__label {
  position: relative;
  padding: 1vw 2vw;
  border: none;
  background: transparent;
  cursor: pointer;
  white-space: nowrap;
}

.tabs__label span {
  font-size: 1.2vw;
  font-weight: 500;
}

.tabs__label--active {
  color: #ff6b00;
}

.tabs__label--inactive {
  color: rgba(0, 0, 0, 0.5);
}

.tabs__active-line {
  position: absolute;
  bottom: 0;
  left: 0;
  height: 2px;
  background: #ff6b00;
}

.tabs__content {
  position: relative;
  width: 100%;
  min-height: 24vw;
  padding-top: 2vw;
}

.tabs__panel {
  width: 100%;
  height: 100%;
}

"use client";

import { useLayoutEffect, useRef, useState } from "react";
import gsap from "gsap";
import "./tabs.css";

export default function Tabs({
  tabs = [],
  defaultActiveIndex = 0,
  className = "",
  animationType = "slide",
  slideDistance = 40,
}) {
  const safeDefaultIndex =
    tabs.length > 0 ? Math.min(Math.max(defaultActiveIndex, 0), tabs.length - 1) : 0;

  const [activeTab, setActiveTab] = useState(safeDefaultIndex);
  const labelRefs = useRef([]);
  const contentRefs = useRef([]);
  const activeLineRef = useRef(null);

  const moveActiveLine = (index) => {
    const activeLabel = labelRefs.current[index];
    const activeLine = activeLineRef.current;
    if (!activeLabel || !activeLine) return;

    gsap.to(activeLine, {
      x: activeLabel.offsetLeft,
      width: activeLabel.offsetWidth,
      duration: 0.45,
      ease: "power3.out",
    });
  };

  const animateContent = (currentIndex, nextIndex) => {
    const currentContent = contentRefs.current[currentIndex];
    const nextContent = contentRefs.current[nextIndex];
    if (!currentContent || !nextContent || currentIndex === nextIndex) return;

    const direction = nextIndex > currentIndex ? 1 : -1;
    gsap.killTweensOf([currentContent, nextContent]);

    if (animationType === "slide") {
      gsap.to(currentContent, {
        opacity: 0,
        x: -direction * slideDistance,
        duration: 0.28,
        ease: "power2.out",
        onComplete: () => {
          gsap.set(currentContent, { display: "none", pointerEvents: "none", x: 0 });
          gsap.set(nextContent, {
            display: "block",
            pointerEvents: "auto",
            opacity: 0,
            x: direction * slideDistance,
          });
          gsap.to(nextContent, { opacity: 1, x: 0, duration: 0.38, ease: "power3.out" });
        },
      });
      return;
    }

    gsap.to(currentContent, {
      opacity: 0,
      duration: 0.2,
      ease: "power2.out",
      onComplete: () => {
        gsap.set(currentContent, { display: "none", pointerEvents: "none" });
        gsap.set(nextContent, { display: "block", pointerEvents: "auto", opacity: 0 });
        gsap.to(nextContent, { opacity: 1, duration: 0.35, ease: "power2.out" });
      },
    });
  };

  const handleTabClick = (index) => {
    if (index === activeTab) return;
    animateContent(activeTab, index);
    moveActiveLine(index);
    setActiveTab(index);
  };

  useLayoutEffect(() => {
    if (!tabs.length) return;

    const activeLabel = labelRefs.current[safeDefaultIndex];
    const activeLine = activeLineRef.current;

    if (activeLabel && activeLine) {
      gsap.set(activeLine, {
        x: activeLabel.offsetLeft,
        width: activeLabel.offsetWidth,
      });
    }

    contentRefs.current.forEach((content, index) => {
      if (!content) return;
      gsap.set(content, {
        display: index === safeDefaultIndex ? "block" : "none",
        opacity: index === safeDefaultIndex ? 1 : 0,
        pointerEvents: index === safeDefaultIndex ? "auto" : "none",
        x: 0,
      });
    });
  }, [safeDefaultIndex, tabs]);

  if (!tabs.length) return null;

  return (
    <div className={`tabs ${className}`}>
      <div className="tabs__header">
        <div className="tabs__labels">
          {tabs.map((tab, index) => (
            <button
              key={tab.id || index}
              ref={(element) => {
                labelRefs.current[index] = element;
              }}
              onClick={() => handleTabClick(index)}
              className={`tabs__label ${
                activeTab === index ? "tabs__label--active" : "tabs__label--inactive"
              }`}
              type="button"
            >
              <span>{tab.label}</span>
            </button>
          ))}
        </div>
        <div ref={activeLineRef} className="tabs__active-line" />
      </div>

      <div className="tabs__content">
        {tabs.map((tab, index) => (
          <div
            key={tab.id || index}
            ref={(element) => {
              contentRefs.current[index] = element;
            }}
            className="tabs__panel"
            style={{ display: index === safeDefaultIndex ? "block" : "none", opacity: index === safeDefaultIndex ? 1 : 0 }}
          >
            {tab.content}
          </div>
        ))}
      </div>
    </div>
  );
}
